# Utility module providing helper classes and functions for number processing

class NumberStats:
    """Simple statistics accumulator for integer values"""
    _values: list[int]

    def __init__(self):
        self._values = []

    def add(self, n: int) -> None:
        self._values.append(n)

    def get_count(self) -> int:
        return len(self._values)

    def sum(self) -> int:
        total: int = 0
        for n in self._values:
            total += n
        return total

    def apply_transform(self, transform: (int) -> int) -> NumberStats:
        """Apply a transformation to all stored values"""
        new_stats = NumberStats()
        for n in self._values:
            new_stats.add(transform(n))
        return new_stats

def validate_non_empty(s: str) -> bool:
    """Check if string has non-zero length"""
    return len(s) > 0

def double_value(x: int) -> int:
    """Simple doubling function"""
    return x * 2

def triple_value(x: int) -> int:
    """Simple tripling function"""
    return x * 3
